// Split finance policy text into overlapping chunks for better RAG retrieval
const text = $input.item.json.policyText;
const CHUNK_WORDS = 200;  // words per chunk
const OVERLAP_WORDS = 30; // overlap between chunks to preserve context

const words = text.split(/\s+/).filter(w => w.length > 0);
const chunks = [];
const step = CHUNK_WORDS - OVERLAP_WORDS;

for (let i = 0; i < words.length; i += step) {
  const slice = words.slice(i, i + CHUNK_WORDS);
  if (slice.length < 15) break; // skip tiny trailing fragments

  const chunkIndex = Math.floor(i / step);
  chunks.push({
    json: {
      chunkId: `finance-policy-chunk-${chunkIndex}`,
      chunkText: slice.join(' '),
      chunkIndex
    }
  });
}

console.log(`Created ${chunks.length} chunks from policy text`);
return chunks;
